.darma-loader-darma-custom-373 {color: var(--loader-color, #0891b2);
  --loader-secondary-color: var(--loader-secondary-color, #22d3ee);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 60px;
  height: 60px;
  display: grid;
}.darma-loader-darma-custom-373:before,.darma-loader-darma-custom-373:after {content: "";
  grid-area: 1/1;
  background: var(--loader-color, #0891b2);
  clip-path: polygon(0 0,100% 0,100% 100%,75% 25%,0 0,0 100%,100% 100%,25% 75%,0 0);
  animation: darma-loader-darma-custom-373-l20 1.5s infinite linear;
}.darma-loader-darma-custom-373:before {clip-path: polygon(0 0,76% 24%,100% 100%,24% 76%);
  --s:0;
}@keyframes darma-loader-darma-custom-373-l20 {0% {transform: perspective(100px) rotate3d(1,var(--s,1),0,0) }25% {transform: perspective(100px) rotate3d(1,var(--s,1),0,-90deg) }25.01% {transform: perspective(100px) rotate3d(1,var(--s,1),0,-90deg) }40%,60% {transform: perspective(100px) rotate3d(1,var(--s,1),0,-180deg)}75% {transform: perspective(100px) rotate3d(1,var(--s,1),0,-270deg)}75.01% {transform: perspective(100px) rotate3d(1,var(--s,1),0,-270deg)}90%,100%{transform: perspective(100px) rotate3d(1,var(--s,1),0,-360deg)}}

